'use client'

import { useEffect, useMemo, useState, useTransition } from 'react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'
import { ChevronLeft, ChevronRight, CircleDollarSign, ClockAlert, FileText, LayoutDashboard, Monitor, Plus, Search, Trash2, WalletCards, X } from 'lucide-react'
import { toast } from 'sonner'
import { buyoutRentalItem, changeStatus, collectPayment, createRental, deleteTestRental, getCustomerHistory, getNextRentalNumbers, recordDepositAction, renewRentalItems, reversePayment, type PaymentInput, type RentalInput, type RentalItemInput, type RenewalInput } from '@/app/actions/rentals'
import { exchangeRentalItem, reportLostItem, returnRentalItem, type ExchangeInput, type LossInput, type ReturnInput } from '@/app/actions/operations'
import { changeRentalItem, createRepairRecord, type RentalChangeInput, type RepairInput } from '@/app/actions/rental-events'
import { getDeviceConfigRows } from '@/lib/device-config'

type Item = { id:number; rentalId:number; deviceName:string; deviceType:string; deviceCode:string|null; deviceConfig:string|null; quantity:number; startDate:string|null; endDate:string|null; monthlyRent:string; totalRent:string; boughtOutQuantity:number; returnedQuantity:number; lostQuantity:number; buyoutAmount:string; cpu:string|null;motherboard:string|null;memory:string|null;storage:string|null;graphicsCard:string|null;powerSupply:string|null;caseModel:string|null;monitorInfo:string|null;screenSize:string|null;screenResolution:string|null;refreshRate:string|null;panelType:string|null;ports:string|null;batteryInfo:string|null;adapterInfo:string|null;accessories:string|null;colorGamut:string|null }
type Buyout = { id:number; rentalItemId:number; quantity:number; unitPrice:string; amount:string; buyoutDate:string; notes:string|null }
type Renewal = { id:number; rentalId:number; sourceRentalItemId:number; renewedRentalItemId:number; quantity:number; renewalMonths:number|null; billingUnit:string|null; duration:number|null; unitPrice:string|null; oldMonthlyRent:string; newMonthlyRent:string; oldEndDate:string; newEndDate:string; renewalAmount:string; renewalDate:string; notes:string|null }
type Payment = { id:number; rentalId:number; renewalRecordId:number|null; amount:string; paymentDate:string; paymentMethod:string; feeType:string; notes:string|null }
type RentalEvent = { id:number;eventType:string;status:string;eventDate:string;itemId:number|null;beforeSnapshot:unknown;afterSnapshot:unknown;reason:string|null;feeAdjustment:string;repairCost:string;customerCharge:string;faultDescription:string|null;resolution:string|null;completedDate:string|null;operatorName:string;notes:string|null }
type Bill = { id:number;billNo:string;periodStart:string;periodEnd:string;dueDate:string;billType:string;amount:string;paidAmount:string;status:string;notes:string|null }
type Ledger = { id:number;entryType:string;amount:string;entryDate:string;paymentRecordId:number|null;operatorName:string;notes:string|null }
type Rental = { id:number;contractNo:string;customerCompany:string|null;customerName:string;customerPhone:string;customerAddress:string|null;deviceName:string;deviceType:string;quantity:number;startDate:string;endDate:string;monthlyRent:string;totalRent:string;deposit:string;paidAmount:string;paymentStatus:string;status:string;notes:string|null;items:Item[];buyoutRecords:Buyout[];renewalRecords:Renewal[];paymentRecords:Payment[];events:RentalEvent[];bills:Bill[];ledger:Ledger[] }
type Summary={total:number;active:number;overdue:number;revenue:string;receivable:string}
const money=(n:string|number)=>new Intl.NumberFormat('zh-CN',{style:'currency',currency:'CNY',maximumFractionDigits:0}).format(Number(n))
const today=()=>new Intl.DateTimeFormat('en-CA',{timeZone:'Asia/Shanghai',year:'numeric',month:'2-digit',day:'2-digit'}).format(new Date())
function calculateEndDate(startDate:string,billingType:'monthly'|'daily',duration:number){if(!startDate)return '';const length=Math.max(1,Math.floor(duration||1));return billingType==='daily'?addDays(startDate,length-1):addDays(addMonths(startDate,length),-1)}
const emptyItem=():RentalItemInput=>({deviceName:'',deviceType:'台式机',deviceCode:'',deviceConfig:'',quantity:1,monthlyRent:0,totalRent:0,cpu:'',motherboard:'',memory:'',storage:'',graphicsCard:'',powerSupply:'',caseModel:'',monitorInfo:'',screenSize:'',screenResolution:'',refreshRate:'',panelType:'',ports:'',batteryInfo:'',adapterInfo:'',accessories:'',colorGamut:''})
const emptyRental=():RentalInput=>{const startDate=today();return {contractNo:'',customerCompany:'',customerName:'',customerPhone:'',customerAddress:'',billingType:'monthly',duration:1,startDate,endDate:calculateEndDate(startDate,'monthly',1),deposit:0,notes:'',items:[emptyItem()]}}

export function Dashboard({role,summary,rentals}:{role:'admin'|'employee';summary:Summary;rentals:Rental[]}){
  const router=useRouter(); const[pending,start]=useTransition(); const[query,setQuery]=useState(''); const[status,setStatus]=useState('全部'); const[page,setPage]=useState(1); const[dialog,setDialog]=useState<'new'|'detail'|'renew'|'payment'|'buyout'|'history'|'return'|'loss'|'change'|'repair'|'deposit'|'exchange'|null>(null); const[selected,setSelected]=useState<Rental|null>(null); const[form,setForm]=useState<RentalInput>(emptyRental())
  const filtered=useMemo(()=>rentals.filter(r=>(status==='全部'||r.status===status)&&`${r.contractNo}${r.customerCompany||''}${r.customerName}${r.customerPhone}${r.deviceName}`.toLowerCase().includes(query.toLowerCase())),[rentals,query,status])
  const pageSize=8; const pageCount=Math.max(1,Math.ceil(filtered.length/pageSize)); const visible=filtered.slice((page-1)*pageSize,page*pageSize)
  useEffect(()=>setPage(1),[query,status])
  useEffect(()=>{if(page>pageCount)setPage(pageCount)},[page,pageCount])
  useEffect(()=>{if(role!=='admin')return;const backup=()=>fetch('/api/backups',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({type:'scheduled'})}).catch(()=>undefined);void backup();const timer=window.setInterval(backup,30*60*1000);return()=>window.clearInterval(timer)},[role])
  const run=(fn:()=>Promise<void>,message:string)=>start(async()=>{try{await fn();toast.success(message);setDialog(null);router.refresh()}catch(error){toast.error(error instanceof Error?error.message:'操作失败')}})
  const openDetail=(r:Rental)=>{setSelected(r);setDialog('detail')}
  return <div className="bg-background">

  <div className="p-4 md:p-6"><div className="mx-auto flex max-w-7xl flex-col gap-6"><div className="flex flex-col justify-between gap-3 sm:flex-row sm:items-center"><div><h1 className="text-2xl font-bold text-balance">经营总览</h1><p className="text-sm text-muted-foreground">管理合同、设备明细、收款与买断进度</p></div><button onClick={()=>{setForm(emptyRental());setDialog('new')}} className="flex h-10 items-center justify-center gap-2 rounded-lg bg-primary px-4 font-medium text-primary-foreground"><Plus className="size-4"/>新增租赁</button></div>
  <div className="grid grid-cols-2 gap-3 lg:grid-cols-4"><Stat label="租赁合同" value={summary.total} icon={<Monitor/>}/><Stat label="在租合同" value={summary.active} icon={<LayoutDashboard/>}/><Stat label="逾期合同" value={summary.overdue} icon={<ClockAlert/>}/><Stat label="累计收款" value={money(summary.revenue)} icon={<WalletCards/>}/></div>
  <section className="overflow-hidden rounded-xl border bg-card"><div className="flex flex-col gap-3 border-b p-4 sm:flex-row sm:items-center sm:justify-between"><div><h2 className="font-semibold">租赁记录</h2><p className="text-sm text-muted-foreground">共 {filtered.length} 条记录</p></div><div className="flex gap-2"><label className="flex h-10 min-w-0 flex-1 items-center gap-2 rounded-lg border px-3 sm:w-72"><Search className="size-4 text-muted-foreground"/><input value={query} onChange={e=>setQuery(e.target.value)} className="min-w-0 flex-1 bg-transparent text-sm outline-none" placeholder="合同、客户或设备"/></label><select aria-label="租赁状态" value={status} onChange={e=>setStatus(e.target.value)} className="h-10 rounded-lg border bg-background px-3">{['全部','在租','逾期','部分买断','部分退租','部分丢失','丢失','买断','已退租','已结束','已关闭'].map(s=><option key={s}>{s}</option>)}</select></div></div>
  <div className="overflow-x-auto"><table className="w-full min-w-[900px] text-left text-sm"><thead className="bg-muted text-muted-foreground"><tr><th className="p-3">合同编号</th><th className="p-3">客户</th><th className="p-3">设备明细</th><th className="p-3">数量</th><th className="p-3">租期</th><th className="p-3">租金总额</th><th className="p-3">状态</th></tr></thead><tbody>{visible.map(r=><tr key={r.id} onClick={()=>openDetail(r)} className="cursor-pointer border-t hover:bg-muted/50"><td className="p-3 font-medium">{r.contractNo}</td><td className="p-3"><p className="font-medium">{r.customerCompany||r.customerName}</p><p className="text-xs text-muted-foreground">{r.customerCompany?`${r.customerName} · `:''}{r.customerPhone}</p></td><td className="p-3">{r.items.length} 项 · {r.items.map(i=>`${i.deviceType} ${i.deviceName}`).join('、')}</td><td className="p-3">{r.quantity}</td><td className="p-3">{r.startDate} 至 {r.endDate}</td><td className="p-3">{money(r.totalRent)}</td><td className="p-3"><Status value={r.status}/></td></tr>)}</tbody></table>{!filtered.length&&<p className="p-10 text-center text-sm text-muted-foreground">暂无符合条件的租赁记录</p>}</div>{filtered.length>pageSize&&<div className="flex items-center justify-between border-t px-4 py-3"><p className="text-xs text-muted-foreground">第 {page} / {pageCount} 页</p><div className="flex gap-2"><button type="button" aria-label="上一页" disabled={page===1} onClick={()=>setPage(value=>Math.max(1,value-1))} className="rounded-lg border p-2 disabled:opacity-40"><ChevronLeft className="size-4"/></button><button type="button" aria-label="下一页" disabled={page===pageCount} onClick={()=>setPage(value=>Math.min(pageCount,value+1))} className="rounded-lg border p-2 disabled:opacity-40"><ChevronRight className="size-4"/></button></div></div>}</section></div></div>
  <Dialog open={dialog==='new'} title="新增租赁合同" wide onClose={()=>setDialog(null)}><RentalForm form={form} setForm={setForm} pending={pending} submit={()=>run(()=>createRental(form),'租赁合同已创建')}/></Dialog>
  <Dialog open={dialog==='detail'} title={selected?.contractNo||'租赁详情'} wide onClose={()=>setDialog(null)}>{selected&&<Detail rental={selected} role={role} onDelete={()=>{if(window.confirm(`确定永久删除测试订单 ${selected.contractNo} 吗？\n\n只有尚未收款、续租、退租、买断或产生其他业务记录的订单可以删除，此操作无法撤销。`))run(()=>deleteTestRental(selected.id),'测试订单已删除')}} onPayment={()=>setDialog('payment')} onRenew={()=>setDialog('renew')} onBuyout={()=>setDialog('buyout')} onHistory={()=>setDialog('history')} onReturn={()=>setDialog('return')} onLoss={()=>setDialog('loss')} onChange={()=>setDialog('change')} onRepair={()=>setDialog('repair')} onDeposit={()=>setDialog('deposit')} onExchange={()=>setDialog('exchange')} onReverse={paymentId=>run(()=>reversePayment(paymentId,'收款录入错误'),'收款已冲正')} onStatus={s=>run(()=>changeStatus(selected.id,s),'状态已更新')}/>}</Dialog>
  <Dialog open={dialog==='payment'} title="登记收款" onClose={()=>setDialog('detail')}>{selected&&<PaymentForm pending={pending} submit={value=>run(()=>collectPayment(selected.id,value),'收款已登记')}/>}</Dialog>
  <Dialog open={dialog==='renew'} title="办理部分设备续租" wide onClose={()=>setDialog('detail')}>{selected&&<RenewalForm rental={selected} pending={pending} submit={values=>run(()=>renewRentalItems(selected.id,values),'续租已办理')}/>}</Dialog>
  <Dialog open={dialog==='history'} title="客户历史记录" wide onClose={()=>setDialog('detail')}>{selected&&<CustomerHistory phone={selected.customerPhone}/>}</Dialog>
  <Dialog open={dialog==='return'} title="办理设备退租" onClose={()=>setDialog('detail')}>{selected&&<OperationForm rental={selected} mode="return" pending={pending} submit={value=>run(()=>returnRentalItem(value as ReturnInput),'退租已登记')}/>}</Dialog>
  <Dialog open={dialog==='loss'} title="登记设备丢失" onClose={()=>setDialog('detail')}>{selected&&<OperationForm rental={selected} mode="loss" pending={pending} submit={value=>run(()=>reportLostItem(value as LossInput),'丢失已登记')}/>}</Dialog>
  <Dialog open={dialog==='change'} title="变更配置与租金" wide onClose={()=>setDialog('detail')}>{selected&&<ChangeForm rental={selected} pending={pending} submit={value=>run(()=>changeRentalItem(value),'配置与应收已更新')}/>}</Dialog>
  <Dialog open={dialog==='repair'} title="登记维修单" wide onClose={()=>setDialog('detail')}>{selected&&<RepairForm rental={selected} pending={pending} submit={value=>run(()=>createRepairRecord(value),'维修记录已保存')}/>}</Dialog>
  <Dialog open={dialog==='deposit'} title="押金退还或抵扣" onClose={()=>setDialog('detail')}>{selected&&<DepositForm rental={selected} pending={pending} submit={(type,amount,date,notes)=>run(()=>recordDepositAction(selected.id,type,amount,date,notes),'押金流水已登记')}/>}</Dialog>
  <Dialog open={dialog==='exchange'} title="设备换机调拨" onClose={()=>setDialog('detail')}>{selected&&<ExchangeForm rental={selected} pending={pending} submit={value=>run(()=>exchangeRentalItem(value),'换机调拨已登记')}/>}</Dialog>
  <Dialog open={dialog==='buyout'} title="办理部分买断" onClose={()=>setDialog('detail')}>{selected&&<BuyoutForm rental={selected} pending={pending} submit={(itemId,quantity,price,date,notes)=>run(()=>buyoutRentalItem(selected.id,itemId,quantity,price,date,notes),'买断已登记')}/>}</Dialog>
  </div>
}

const configs:Record<string,[keyof RentalItemInput,string,string][]>= {
  台式机:[['cpu','CPU','Intel i5-12400'],['motherboard','主板','华硕 B660M'],['memory','内存','16GB DDR4'],['storage','硬盘','512GB SSD'],['graphicsCard','显卡','RTX 3060'],['powerSupply','电源','550W'],['caseModel','机箱','MATX 机箱']],
  笔记本:[['cpu','CPU','Core Ultra 7'],['memory','内存','16GB'],['storage','硬盘','1TB SSD'],['graphicsCard','显卡','Intel Arc'],['screenSize','屏幕尺寸','14 英寸'],['screenResolution','分辨率','2560 × 1600'],['batteryInfo','电池信息','57Wh / 健康度 95%'],['adapterInfo','适配器','65W Type-C']],
  显示器:[['screenSize','屏幕尺寸','27 英寸'],['screenResolution','分辨率','2560 × 1440'],['refreshRate','刷新率','165Hz'],['panelType','面板','IPS'],['colorGamut','色域','99% sRGB'],['ports','接口','HDMI / DP'],['monitorInfo','支架功能','升降旋转'],['accessories','配件','电源线、DP 线']],
  一体机:[['cpu','CPU','Intel i5'],['memory','内存','16GB'],['storage','硬盘','512GB SSD'],['graphicsCard','显卡','Intel UHD'],['screenSize','屏幕尺寸','24 英寸'],['screenResolution','分辨率','1920 × 1080'],['ports','接口','USB / HDMI / 网口'],['accessories','配件','无线键鼠']],
}
const configTemplates:Record<string,Array<{name:string;values:Partial<RentalItemInput>}>>={
  台式机:[{name:'办公基础款',values:{deviceName:'办公台式机',cpu:'Intel i5-12400',motherboard:'B660M',memory:'16GB DDR4',storage:'512GB SSD',graphicsCard:'核芯显卡',powerSupply:'500W',caseModel:'商务机箱'}},{name:'设计性能款',values:{deviceName:'设计台式机',cpu:'Intel i7-12700',motherboard:'B660M',memory:'32GB DDR4',storage:'1TB SSD',graphicsCard:'RTX 3060',powerSupply:'650W',caseModel:'MATX 机箱'}}],
  笔记本:[{name:'商务办公款',values:{deviceName:'商务笔记本',cpu:'Intel i5',memory:'16GB',storage:'512GB SSD',graphicsCard:'核芯显卡',screenSize:'14 英寸',screenResolution:'1920 × 1080',adapterInfo:'65W 电源适配器'}},{name:'移动性能款',values:{deviceName:'高性能笔记本',cpu:'Intel i7',memory:'32GB',storage:'1TB SSD',graphicsCard:'RTX 4060',screenSize:'16 英寸',screenResolution:'2560 × 1600',adapterInfo:'原装电源适配器'}}],
  显示器:[{name:'办公显示器',values:{deviceName:'办公显示器',screenSize:'24 英寸',screenResolution:'1920 × 1080',refreshRate:'75Hz',panelType:'IPS',ports:'HDMI',accessories:'电源线、HDMI 线'}},{name:'设计显示器',values:{deviceName:'设计显示器',screenSize:'27 英寸',screenResolution:'2560 × 1440',refreshRate:'100Hz',panelType:'IPS',colorGamut:'99% sRGB',ports:'HDMI / DP',accessories:'电源线、DP 线'}}],
  一体机:[{name:'办公一体机',values:{deviceName:'办公一体机',cpu:'Intel i5',memory:'16GB',storage:'512GB SSD',graphicsCard:'核芯显卡',screenSize:'24 英寸',screenResolution:'1920 × 1080',accessories:'无线键鼠'}}],
}
function RentalForm({form,setForm,submit,pending}:{form:RentalInput;setForm:(form:RentalInput)=>void;submit:()=>void;pending:boolean}){
  const [step,setStep]=useState(0)
  const [error,setError]=useState('')
  const billingType=form.billingType||'monthly'
  const duration=Math.max(1,form.duration||1)
  const suggestedTotal=(item:RentalItemInput)=>Math.max(0,item.quantity*item.monthlyRent*duration)
  useEffect(()=>{let active=true;const timer=setTimeout(()=>{getNextRentalNumbers(form.startDate,form.items.map(item=>({deviceType:item.deviceType,quantity:Math.max(1,item.quantity||1)}))).then(numbers=>{if(active)setForm({...form,contractNo:numbers.contractNo,items:form.items.map((item,index)=>({...item,deviceCode:numbers.deviceCodes[index]}))})}).catch(()=>{})},150);return()=>{active=false;clearTimeout(timer)}},[form.startDate,form.items.map(item=>`${item.deviceType}:${item.quantity}`).join('|')])
  const updateItem=(index:number,key:keyof RentalItemInput,value:string|number)=>{const items=form.items.map((item,i)=>{if(i!==index)return item;const next={...item,[key]:value};if(key==='quantity'||key==='monthlyRent')next.totalRent=suggestedTotal(next);return next});setForm({...form,items})}
  useEffect(()=>{const endDate=calculateEndDate(form.startDate,billingType,duration);const items=form.items.map(item=>({...item,totalRent:suggestedTotal(item)}));if(endDate!==form.endDate||items.some((item,index)=>item.totalRent!==form.items[index].totalRent))setForm({...form,endDate,items})},[form.startDate,billingType,duration])
  const totals=form.items.reduce((a,i)=>({qty:a.qty+i.quantity,monthly:a.monthly+i.monthlyRent*i.quantity,total:a.total+i.totalRent}),{qty:0,monthly:0,total:0})
  const validate=()=>{if(step===0&&(!form.contractNo.trim()||!form.customerName.trim()||!/^1\d{10}$/.test(form.customerPhone.trim())))return '请填写合同编号、联系人和正确的 11 位手机号';if(step===1&&form.items.some(item=>!item.deviceName.trim()||item.quantity<1||item.monthlyRent<=0))return '请完整填写设备名称，并确保数量不少于 1';if(step===2&&(!form.startDate||duration<1||form.endDate!==calculateEndDate(form.startDate,billingType,duration)))return '请填写正确的起租日期和租赁时间';return ''}
  const next=()=>{const message=validate();if(message){setError(message);return}setError('');setStep(current=>Math.min(2,current+1))}
  const confirmSubmit=()=>{const message=validate();if(message){setError(message);return}setError('');submit()}
  const steps=['客户与合同','设备明细','租期与费用']
  return <form onSubmit={e=>e.preventDefault()} onKeyDown={e=>{if(e.key==='Enter'&&!e.nativeEvent.isComposing&&e.keyCode!==229&&e.target instanceof HTMLInputElement)e.preventDefault()}} className="flex min-h-[34rem] flex-col gap-5"><nav aria-label="新增租赁步骤" className="grid grid-cols-3 gap-2 rounded-xl bg-muted p-2">{steps.map((label,index)=><button key={label} type="button" onClick={()=>index<step&&setStep(index)} className={`rounded-lg px-3 py-2 text-sm font-medium ${index===step?'bg-primary text-primary-foreground':'text-muted-foreground'}`}><span className="mr-1">{index+1}.</span>{label}</button>)}</nav>{step===0&&<FormSection title="合同与客户" description="一份合同可包含多项不同设备配置"><div className="grid gap-4 sm:grid-cols-2"><Field label="合同编号" value={form.contractNo||'正在生成…'} onChange={()=>{}} readOnly placeholder="按起租日期自动生成"/><Field label="客户公司名称" value={form.customerCompany||''} onChange={v=>setForm({...form,customerCompany:v})} required={false} placeholder="选填，如：某某科技有限公司"/><Field label="联系人姓名" value={form.customerName} onChange={v=>setForm({...form,customerName:v})} placeholder="必填，请输入联系人姓名"/><Field label="联系电话" value={form.customerPhone} onChange={v=>setForm({...form,customerPhone:v.replace(/\D/g,'').slice(0,11)})} placeholder="必填，请输入 11 位手机号"/><Field label="客户地址" value={form.customerAddress||''} onChange={v=>setForm({...form,customerAddress:v})} required={false} placeholder="选填，设备交付地址"/></div></FormSection>}
  {step===1&&<FormSection title={`设备明细（${form.items.length} 项）`} description={`每项设备可独立设置配置、数量、${billingType==='daily'?'日租':'月租'}单价和合同金额`}><div className="flex flex-col gap-4">{form.items.map((item,index)=><div key={index} className="rounded-xl border bg-muted/30 p-4"><div className="mb-4 flex items-center justify-between"><h3 className="font-semibold">设备明细 {index+1}</h3>{form.items.length>1&&<button type="button" aria-label={`删除设备明细 ${index+1}`} onClick={()=>setForm({...form,items:form.items.filter((_,i)=>i!==index)})} className="rounded-lg border p-2 text-destructive"><Trash2 className="size-4"/></button>}</div><div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3"><label className="flex flex-col gap-2 text-sm font-medium">设备类型<select className="h-10 rounded-lg border bg-background px-3" value={item.deviceType} onChange={e=>updateItem(index,'deviceType',e.target.value)}>{['台式机','笔记本','显示器','一体机','其他'].map(v=><option key={v}>{v}</option>)}</select></label><Field label="设备名称 / 型号" value={item.deviceName} onChange={v=>updateItem(index,'deviceName',v)}/><Field label="设备编号 / 编号范围" value={item.deviceCode||'正在生成…'} onChange={()=>{}} readOnly placeholder="按类型和数量自动生成"/><Field label="数量" type="number" value={item.quantity} onChange={v=>updateItem(index,'quantity',Number(v))}/><Field label={`${billingType==='daily'?'日租':'月租'}单价（元/台）`} type="number" value={item.monthlyRent} onChange={v=>updateItem(index,'monthlyRent',Number(v))}/><div className="flex flex-col gap-2"><Field label="明细租金总额（自动计算）" type="number" value={item.totalRent} onChange={()=>{}} readOnly/><p className="text-xs text-muted-foreground">按数量 × 单价 × 租期自动计算：{money(suggestedTotal(item))}</p></div></div>{configTemplates[item.deviceType]?.length&&<div className="mt-4 flex flex-wrap items-center gap-2"><span className="text-xs font-medium text-muted-foreground">常用配置：</span>{configTemplates[item.deviceType].map(template=><button key={template.name} type="button" onClick={()=>{const items=form.items.map((current,i)=>i===index?{...current,...template.values}:current);setForm({...form,items})}} className="rounded-lg border bg-background px-3 py-1.5 text-xs font-medium hover:bg-muted">{template.name}</button>)}</div>}{configs[item.deviceType]&&<div className="mt-4 grid gap-4 sm:grid-cols-2 lg:grid-cols-4">{configs[item.deviceType].map(([key,label,placeholder])=><Field key={key} label={label} value={String(item[key]||'')} placeholder={placeholder} onChange={v=>updateItem(index,key,v)}/>)}</div>}<div className="mt-4"><Field label="其他配置" value={item.deviceConfig||''} onChange={v=>updateItem(index,'deviceConfig',v)} required={false}/></div></div>)}<button type="button" onClick={()=>setForm({...form,items:[...form.items,emptyItem()]})} className="flex h-10 items-center justify-center gap-2 rounded-lg border border-dashed font-medium"><Plus className="size-4"/>添加另一项设备</button></div></FormSection>}
  {step===2&&<><FormSection title="租期与费用" description="选择计费方式并填写租赁时间，到期日和合同金额将自动计算"><div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3"><label className="flex flex-col gap-2 text-sm font-medium">计费方式<select className="h-10 rounded-lg border bg-background px-3" value={billingType} onChange={e=>setForm({...form,billingType:e.target.value as 'monthly'|'daily'})}><option value="monthly">月租</option><option value="daily">日租</option></select></label><label className="flex flex-col gap-2 text-sm font-medium">{`租赁时间（${billingType==='daily'?'天':'个月'}）`}<input className="h-10 rounded-lg border bg-background px-3 outline-none focus:ring-2 focus:ring-primary" type="number" min="1" step="1" inputMode="numeric" value={form.duration||''} placeholder="必填，至少 1" onFocus={e=>e.currentTarget.select()} onChange={e=>setForm({...form,duration:e.target.value===''?0:Math.max(0,Math.floor(Number(e.target.value)))})} onBlur={()=>{if(form.duration<1)setForm({...form,duration:1})}}/></label><Field label="起租日期" type="date" value={form.startDate} onChange={v=>setForm({...form,startDate:v})}/><Field label="到期日期（自动计算）" type="date" value={form.endDate} onChange={()=>{}}/><Field label="押金（元）" type="number" value={form.deposit} onChange={v=>setForm({...form,deposit:Number(v)})}/></div><div className="grid grid-cols-2 gap-3 rounded-xl bg-muted p-4 text-sm sm:grid-cols-4"><Info l="设备总数" v={`${totals.qty} 台`}/><Info l={`${billingType==='daily'?'日租':'月租'}单价合计`} v={money(totals.monthly)}/><Info l="租金总额" v={money(totals.total)}/><Info l="应收总额（含押金）" v={money(totals.total+Number(form.deposit||0))}/></div></FormSection><FormSection title="业务备注" description="填写交付要求、软件环境或其他约定"><textarea className="min-h-24 rounded-lg border bg-background p-3" value={form.notes||''} onChange={e=>setForm({...form,notes:e.target.value})}/></FormSection></>}{error&&<p role="alert" className="rounded-lg bg-destructive/10 px-4 py-3 text-sm text-destructive">{error}</p>}<div className="sticky bottom-0 -mx-1 mt-auto flex items-center justify-between border-t bg-background/95 px-1 py-4 backdrop-blur"><button type="button" disabled={step===0} onClick={()=>{setError('');setStep(current=>Math.max(0,current-1))}} className="h-10 rounded-lg border px-5 font-medium disabled:opacity-40">上一步</button><span className="text-sm text-muted-foreground">第 {step+1} / 3 步</span>{step<2?<button type="button" onClick={next} className="h-10 rounded-lg bg-primary px-5 font-medium text-primary-foreground">下一步</button>:<button type="button" disabled={pending} onClick={confirmSubmit} className="h-10 rounded-lg bg-primary px-5 font-medium text-primary-foreground disabled:opacity-60">{pending?'正在保存':'确认并保存合同'}</button>}</div></form>
}

function Detail({rental,role,onDelete,onPayment,onRenew,onBuyout,onHistory,onReturn,onLoss,onChange,onRepair,onDeposit,onExchange,onReverse,onStatus}:{rental:Rental;role:'admin'|'employee';onDelete:()=>void;onPayment:()=>void;onRenew:()=>void;onBuyout:()=>void;onHistory:()=>void;onReturn:()=>void;onLoss:()=>void;onChange:()=>void;onRepair:()=>void;onDeposit:()=>void;onExchange:()=>void;onReverse:(paymentId:number)=>void;onStatus:(s:string)=>void}){return <div className="flex flex-col gap-5">{role==='admin'&&<section className="flex flex-col gap-3 rounded-xl border border-destructive/30 bg-destructive/5 p-4 sm:flex-row sm:items-center sm:justify-between"><div><h3 className="font-semibold">管理员订单管理</h3><p className="text-sm text-muted-foreground">测试订单可永久删除；已有业务记录的订单请关闭并保留记录。</p></div><div className="flex gap-2"><button type="button" disabled={rental.status==='已关闭'} onClick={()=>onStatus('已关闭')} className="rounded-lg border bg-background px-4 py-2 text-sm font-medium disabled:opacity-50">{rental.status==='已关闭'?'订单已关闭':'关闭订单'}</button><button type="button" onClick={onDelete} className="flex items-center gap-2 rounded-lg bg-destructive px-4 py-2 text-sm font-medium text-destructive-foreground"><Trash2 className="size-4"/>删除测试订单</button></div></section>}<div className="grid grid-cols-2 gap-4 rounded-xl bg-muted p-4 text-sm sm:grid-cols-4"><Info l="客户公司" v={rental.customerCompany||'个人客户'}/><Info l="联系人" v={rental.customerName}/><Info l="联系电话" v={rental.customerPhone}/><Info l="租期" v={`${rental.startDate} 至 ${rental.endDate}`}/><Info l="状态" v={rental.status}/><Info l="设备总数" v={`${rental.quantity} 台`}/><Info l="租金总额" v={money(rental.totalRent)}/><Info l="已收租金" v={money(rental.paidAmount)}/><Info l="约定押金" v={money(rental.deposit)}/></div><div className="flex flex-col gap-3"><h3 className="font-semibold">设备明细</h3>{rental.items.map(item=>{const remain=item.quantity-item.boughtOutQuantity;return <article key={item.id} className="rounded-xl border p-4"><div className="flex flex-col justify-between gap-2 sm:flex-row"><div><p className="font-semibold">{item.deviceType} · {item.deviceName}</p><p className="text-sm text-muted-foreground">{item.deviceCode||''}</p></div><Status value={remain===0?'已买断':item.boughtOutQuantity>0?'部分买断':'在租'}/></div><div className="mt-4 grid grid-cols-2 gap-3 text-sm sm:grid-cols-4"><Info l="原数量" v={`${item.quantity} 台`}/><Info l="已买断" v={`${item.boughtOutQuantity} 台`}/><Info l="剩余在租" v={`${remain} 台`}/><Info l="买断金额" v={money(item.buyoutAmount)}/><Info l="月租单价 / 台" v={money(item.monthlyRent)}/><Info l="设备租期" v={`${item.startDate||rental.startDate} 至 ${item.endDate||rental.endDate}`}/></div><dl className="mt-3 grid grid-cols-2 gap-x-4 gap-y-2 text-sm sm:grid-cols-4">{getDeviceConfigRows(item).map(row=><div key={row.label}><dt className="text-xs text-muted-foreground">{row.label}</dt><dd className="min-h-5">{row.value}</dd></div>)}</dl></article>})}</div>{rental.bills.length>0&&<section><h3 className="mb-3 font-semibold">月度应收账单</h3><div className="flex flex-col gap-2">{rental.bills.map(bill=><div key={bill.id} className="flex flex-wrap items-center justify-between gap-2 rounded-lg border p-3 text-sm"><span>{bill.periodStart} 至 {bill.periodEnd} · {bill.billType}</span><span>{money(bill.paidAmount)} / {money(bill.amount)} · {bill.status}</span></div>)}</div></section>}{rental.paymentRecords.length>0&&<section><h3 className="mb-3 font-semibold">收款与冲正</h3><div className="flex flex-col gap-2">{rental.paymentRecords.map(payment=><div key={payment.id} className="flex flex-wrap items-center justify-between gap-2 rounded-lg border p-3 text-sm"><span>{payment.paymentDate} · {payment.feeType} · {money(payment.amount)}</span>{Number(payment.amount)>0&&<button type="button" onClick={()=>onReverse(payment.id)} className="rounded-lg border px-3 py-1.5 text-destructive">冲正</button>}</div>)}</div></section>}{rental.events.length>0&&<section><h3 className="mb-3 font-semibold">变更与维修记录</h3><div className="flex flex-col gap-2">{rental.events.map(event=><article key={event.id} className="rounded-lg border p-3 text-sm"><div className="flex flex-wrap items-center justify-between gap-2"><strong>{event.eventType} · {event.eventDate}</strong><Status value={event.status}/></div><p className="mt-1 text-muted-foreground">{event.eventType==='维修'?`${event.faultDescription||'维修记录'} · 客户承担 ${money(event.customerCharge)}`:`${event.reason||'配置调整'} · 应收调整 ${money(event.feeAdjustment)}`}</p><p className="mt-1 text-xs text-muted-foreground">经办人：{event.operatorName}{event.notes?` · ${event.notes}`:''}</p></article>)}</div></section>}{rental.renewalRecords.length>0&&<div><h3 className="mb-3 font-semibold">续租记录</h3><div className="flex flex-col gap-2">{rental.renewalRecords.map(record=>{const item=rental.items.find(i=>i.id===record.renewedRentalItemId)||rental.items.find(i=>i.id===record.sourceRentalItemId);return <div key={record.id} className="rounded-lg border p-3 text-sm"><div className="flex flex-col justify-between gap-1 sm:flex-row"><strong>{item?.deviceName||'设备明细'} · {record.quantity} 台 · 续租 {record.renewalMonths||'—'} 个月</strong><span>{record.renewalDate}</span></div><p className="mt-1 text-muted-foreground">月租 {money(record.oldMonthlyRent)} → {money(record.newMonthlyRent)} · 到期 {record.oldEndDate} → {record.newEndDate}</p></div>})}</div></div>}{rental.buyoutRecords.length>0&&<div><h3 className="mb-3 font-semibold">买断记录</h3><div className="flex flex-col gap-2">{rental.buyoutRecords.map(record=><div key={record.id} className="flex justify-between rounded-lg border p-3 text-sm"><span>{record.buyoutDate} · {record.quantity} 台 × {money(record.unitPrice)}</span><strong>{money(record.amount)}</strong></div>)}</div></div>}<div className="flex flex-wrap gap-2"><button onClick={onHistory} className="rounded-lg border px-4 py-2 text-sm font-medium">客户历史</button><button onClick={onReturn} className="rounded-lg border px-4 py-2 text-sm font-medium">办理退租</button><button onClick={onLoss} className="rounded-lg border px-4 py-2 text-sm font-medium text-destructive">登记丢失</button><Link href={`/contracts/${rental.id}`} className="inline-flex items-center gap-2 rounded-lg border px-4 py-2 text-sm font-medium"><FileText className="size-4"/>查看合同</Link><button onClick={onDeposit} className="rounded-lg border px-3 py-2 text-sm font-medium">押金处理</button><button onClick={onExchange} className="rounded-lg border px-3 py-2 text-sm font-medium">设备换机</button><button onClick={onChange} className="rounded-lg border px-3 py-2 text-sm font-medium">配置/租金变更</button><button onClick={onRepair} className="rounded-lg border px-3 py-2 text-sm font-medium">登记维修</button><button onClick={onPayment} className="rounded-lg bg-primary px-4 py-2 text-sm font-medium text-primary-foreground">登记收款</button><button onClick={onRenew} className="rounded-lg border px-4 py-2 text-sm font-medium">办理续租</button>{rental.items.some(i=>i.boughtOutQuantity<i.quantity)&&<button onClick={onBuyout} className="rounded-lg border px-4 py-2 text-sm font-medium">办理部分买断</button>}<button onClick={()=>onStatus('丢失')} className="rounded-lg border px-4 py-2 text-sm font-medium">标记丢失</button>{!['在租','买断'].includes(rental.status)&&<button onClick={()=>onStatus('在租')} className="rounded-lg border px-4 py-2 text-sm font-medium">恢复在租</button>}</div></div>}
function addMonths(date:string,months=1){const [year,month,day]=date.split('-').map(Number);const target=new Date(Date.UTC(year,month-1+months,1));const lastDay=new Date(Date.UTC(target.getUTCFullYear(),target.getUTCMonth()+1,0)).getUTCDate();target.setUTCDate(Math.min(day,lastDay));return target.toISOString().slice(0,10)}
function addDays(date:string,days=1){const value=new Date(`${date}T00:00:00Z`);value.setUTCDate(value.getUTCDate()+days);return value.toISOString().slice(0,10)}
function RenewalForm({rental,submit,pending}:{rental:Rental;submit:(values:RenewalInput[])=>void;pending:boolean}){
  const available=rental.items.filter(item=>item.quantity>item.boughtOutQuantity)
  const[rows,setRows]=useState<Record<number,RenewalInput>>({})
  const toggle=(item:Item)=>setRows(current=>{const next={...current};if(next[item.id])delete next[item.id];else{const end=item.endDate||rental.endDate;next[item.id]={rentalItemId:item.id,quantity:item.quantity-item.boughtOutQuantity,billingUnit:'month',duration:1,unitPrice:Number(item.monthlyRent),newEndDate:addMonths(end,1),notes:''}}return next})
  const update=(id:number,key:keyof RenewalInput,value:string|number)=>setRows(current=>({...current,[id]:{...current[id],[key]:value}}))
  const selected=Object.values(rows);const totalQty=selected.reduce((sum,row)=>sum+row.quantity,0);const renewalTotal=selected.reduce((sum,row)=>sum+row.quantity*row.unitPrice*row.duration,0)
  return <form onSubmit={e=>{e.preventDefault();submit(selected)}} className="flex flex-col gap-4"><div className="rounded-xl bg-muted p-4 text-sm text-muted-foreground">勾选需要续租的设备，可分别填写续租数量、续租月数和新月租，新到期日将自动计算。部分数量续租时系统会自动拆分，未续租设备保留原租金和到期日。</div><div className="flex flex-col gap-3">{available.map(item=>{const row=rows[item.id];const max=item.quantity-item.boughtOutQuantity;return <article key={item.id} className={`rounded-xl border p-4 ${row?'border-primary bg-primary/5':''}`}><label className="flex cursor-pointer items-start gap-3"><input className="mt-1 size-4" type="checkbox" checked={Boolean(row)} onChange={()=>toggle(item)}/><span><strong>{item.deviceName}</strong><span className="block text-sm text-muted-foreground">{item.deviceType} · 可续租 {max} 台 · 当前月租 {money(item.monthlyRent)} · 到期 {item.endDate||rental.endDate}</span></span></label>{row&&<div className="mt-4 grid gap-4 sm:grid-cols-2 lg:grid-cols-5"><Field label="续租数量" type="number" value={row.quantity} onChange={v=>update(item.id,'quantity',Number(v))}/><label className="flex flex-col gap-2 text-sm font-medium">计费方式<select className="h-10 rounded-lg border bg-background px-3" value={row.billingUnit} onChange={e=>{const unit=e.target.value as 'month'|'day';setRows(current=>({...current,[item.id]:{...current[item.id],billingUnit:unit,duration:1,unitPrice:unit==='month'?Number(item.monthlyRent):Math.round(Number(item.monthlyRent)/30*100)/100,newEndDate:unit==='month'?addMonths(item.endDate||rental.endDate,1):addDays(item.endDate||rental.endDate,1)}}))}}><option value="month">按月</option><option value="day">按天</option></select></label><Field label={`续租${row.billingUnit==='month'?'月数':'天数'}`} type="number" value={row.duration} onChange={v=>{const duration=Math.max(1,Math.floor(Number(v)));setRows(current=>({...current,[item.id]:{...current[item.id],duration,newEndDate:row.billingUnit==='month'?addMonths(item.endDate||rental.endDate,duration):addDays(item.endDate||rental.endDate,duration)}}))}}/><Field label={`每${row.billingUnit==='month'?'月':'天'}单价（元）`} type="number" value={row.unitPrice} onChange={v=>update(item.id,'unitPrice',Number(v))}/><div className="rounded-lg border bg-muted/50 px-3 py-2"><p className="text-sm font-medium">新到期日</p><p className="mt-1 font-semibold">{row.newEndDate}</p><p className="mt-1 text-xs text-muted-foreground">本项 {money(row.quantity*row.unitPrice*row.duration)}</p></div></div>}{row&&row.quantity>max&&<p className="mt-2 text-sm text-destructive">续租数量不能超过 {max} 台</p>}</article>})}</div>{available.length===0&&<p className="py-8 text-center text-sm text-muted-foreground">当前没有可续租设备</p>}<div className="grid grid-cols-2 gap-3 rounded-xl bg-muted p-4"><Info l="本次续租" v={`${totalQty} 台`}/><Info l="续租金额" v={money(renewalTotal)}/></div><button disabled={pending||selected.length===0||selected.some(row=>{const item=available.find(i=>i.id===row.rentalItemId);return !item||row.quantity<=0||row.quantity>item.quantity-item.boughtOutQuantity||row.duration<1||row.duration>3650||row.unitPrice<0||row.newEndDate<=(item.endDate||rental.endDate)})} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground disabled:opacity-50">{pending?'处理中':'确认续租'}</button></form>
}
function PaymentForm({submit,pending}:{submit:(value:PaymentInput)=>void;pending:boolean}){const[value,setValue]=useState<PaymentInput>({amount:0,paymentDate:today(),paymentMethod:'微信',feeType:'原合同租金',notes:''});return <form onSubmit={e=>{e.preventDefault();submit(value)}} className="flex flex-col gap-4"><div className="grid gap-4 sm:grid-cols-2"><Field label="收款金额（元）" type="number" value={value.amount} onChange={v=>setValue({...value,amount:Number(v)})}/><Field label="收款日期" type="date" value={value.paymentDate} onChange={v=>setValue({...value,paymentDate:v})}/><label className="flex flex-col gap-2 text-sm font-medium">支付方式<select className="h-10 rounded-lg border bg-background px-3" value={value.paymentMethod} onChange={e=>setValue({...value,paymentMethod:e.target.value as PaymentInput['paymentMethod']})}>{['现金','微信','支付宝','银行卡','其他'].map(item=><option key={item}>{item}</option>)}</select></label><label className="flex flex-col gap-2 text-sm font-medium">费用类型<select className="h-10 rounded-lg border bg-background px-3" value={value.feeType} onChange={e=>setValue({...value,feeType:e.target.value as PaymentInput['feeType']})}>{['原合同租金','续租费','押金','买断费','其他'].map(item=><option key={item}>{item}</option>)}</select></label></div><label className="flex flex-col gap-2 text-sm font-medium">备注<textarea className="min-h-20 rounded-lg border bg-background p-3" value={value.notes||''} onChange={e=>setValue({...value,notes:e.target.value})}/></label><button disabled={pending||value.amount<=0} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground disabled:opacity-50">{pending?'处理中':'确认收款'}</button></form>}
function CustomerHistory({phone}:{phone:string}){const[data,setData]=useState<Awaited<ReturnType<typeof getCustomerHistory>>|null>(null);const[error,setError]=useState('');useEffect(()=>{getCustomerHistory(phone).then(setData).catch(e=>setError(e instanceof Error?e.message:'查询失败'))},[phone]);if(error)return <p className="text-sm text-destructive">{error}</p>;if(!data)return <p className="py-10 text-center text-sm text-muted-foreground">正在查询客户历史…</p>;const contractMap=new Map(data.contracts.map(c=>[c.id,c.contractNo]));const total=data.contracts.reduce((sum,c)=>sum+Number(c.totalRent),0);const paid=data.payments.reduce((sum,p)=>sum+Number(p.amount),0);return <div className="flex flex-col gap-5"><div className="grid grid-cols-2 gap-3 rounded-xl bg-muted p-4 sm:grid-cols-4"><Info l="手机号" v={phone}/><Info l="历史合同" v={`${data.contracts.length} 份`}/><Info l="累计合同额" v={money(total)}/><Info l="累计收款" v={money(paid)}/></div><section><h3 className="mb-3 font-semibold">合同记录</h3><div className="flex flex-col gap-2">{data.contracts.map(c=><div key={c.id} className="flex flex-col justify-between gap-2 rounded-lg border p-3 text-sm sm:flex-row"><span><strong>{c.contractNo}</strong> · {c.customerName}</span><span>{c.startDate} 至 {c.endDate} · {money(c.totalRent)} · {c.status}</span></div>)}</div></section><section><h3 className="mb-3 font-semibold">续租记录</h3><div className="flex flex-col gap-2">{data.renewals.map(r=><div key={r.id} className="rounded-lg border p-3 text-sm"><strong>{contractMap.get(r.rentalId)} · {r.quantity} 台 · 按{r.billingUnit==='day'?'天':'月'}续租 {r.duration||r.renewalMonths||1} {r.billingUnit==='day'?'天':'个月'}</strong><p className="mt-1 text-muted-foreground">单价 {money(r.unitPrice||r.newMonthlyRent)} · 金额 {money(r.renewalAmount)} · 到期 {r.newEndDate}</p></div>)}{!data.renewals.length&&<p className="text-sm text-muted-foreground">暂无续租记录</p>}</div></section><section><h3 className="mb-3 font-semibold">退租、丢失与设备变更</h3><div className="flex flex-col gap-2">{[...data.returns.map(item=>({id:`return-${item.id}`,date:item.returnDate,title:'设备退租',detail:`${item.quantity} 台 · ${item.condition} · 押金退还 ${money(item.depositRefund)}`,rentalId:item.rentalId})),...data.losses.map(item=>({id:`loss-${item.id}`,date:item.lossDate,title:'设备丢失',detail:`${item.quantity} 台 · 赔偿 ${money(item.amount)}`,rentalId:item.rentalId})),...data.events.map(item=>({id:`event-${item.id}`,date:item.eventDate,title:item.eventType,detail:`${item.status}${item.reason?` · ${item.reason}`:''}`,rentalId:item.rentalId}))].sort((a,b)=>b.date.localeCompare(a.date)).map(item=><div key={item.id} className="rounded-lg border p-3 text-sm"><strong>{item.date} · {item.title}</strong><p className="mt-1 text-muted-foreground">{contractMap.get(item.rentalId)} · {item.detail}</p></div>)}{!data.returns.length&&!data.losses.length&&!data.events.length&&<p className="text-sm text-muted-foreground">暂无退租、丢失或设备变更记录</p>}</div></section><section><h3 className="mb-3 font-semibold">付款记录</h3><div className="flex flex-col gap-2">{data.payments.map(p=><div key={p.id} className="flex flex-col justify-between gap-1 rounded-lg border p-3 text-sm sm:flex-row"><span><strong>{money(p.amount)}</strong> · {p.feeType} · {p.paymentMethod}</span><span>{contractMap.get(p.rentalId)} · {p.paymentDate}{p.notes?` · ${p.notes}`:''}</span></div>)}{!data.payments.length&&<p className="text-sm text-muted-foreground">暂无付款记录</p>}</div></section></div>}
function OperationForm({rental,mode,submit,pending}:{rental:Rental;mode:'return'|'loss';submit:(value:ReturnInput|LossInput)=>void;pending:boolean}){const available=rental.items.filter(i=>i.quantity-i.boughtOutQuantity-i.returnedQuantity-i.lostQuantity>0);const[itemId,setItemId]=useState(available[0]?.id||0);const[quantity,setQuantity]=useState(1);const[date,setDate]=useState(today());const[condition,setCondition]=useState<'完好'|'轻微磨损'|'损坏'>('完好');const[amount,setAmount]=useState(0);const[refund,setRefund]=useState(0);const[notes,setNotes]=useState('');return <form onSubmit={e=>{e.preventDefault();const base={rentalId:rental.id,rentalItemId:itemId,quantity,date,notes};submit(mode==='return'?{...base,condition,deductionAmount:amount,depositRefund:refund}:{...base,unitCompensation:amount})}} className="flex flex-col gap-4"><label className="flex flex-col gap-2 text-sm font-medium">设备明细<select value={itemId} onChange={e=>setItemId(Number(e.target.value))} className="h-10 rounded-lg border bg-background px-3">{available.map(i=><option key={i.id} value={i.id}>{i.deviceType} · {i.deviceName} · {i.deviceCode||'无编号'}（可处理 {i.quantity-i.boughtOutQuantity-i.returnedQuantity-i.lostQuantity} 台）</option>)}</select></label><div className="grid grid-cols-2 gap-4"><Field label="数量" type="number" value={quantity} onChange={v=>setQuantity(Number(v))}/><Field label={mode==='return'?'归还日期':'发生日期'} type="date" value={date} onChange={setDate}/>{mode==='return'&&<label className="flex flex-col gap-2 text-sm font-medium">设备状况<select value={condition} onChange={e=>setCondition(e.target.value as typeof condition)} className="h-10 rounded-lg border bg-background px-3"><option>完好</option><option>轻微磨损</option><option>损坏</option></select></label>}<Field label={mode==='return'?'损坏/清洁扣款（元）':'单台赔偿（元）'} type="number" value={amount} onChange={v=>setAmount(Number(v))}/>{mode==='return'&&<Field label="押金退还（元）" type="number" value={refund} onChange={v=>setRefund(Number(v))}/>}</div><label className="flex flex-col gap-2 text-sm font-medium">备注<textarea className="min-h-20 rounded-lg border bg-background p-3" value={notes} onChange={e=>setNotes(e.target.value)}/></label><button disabled={pending||!available.length} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground">{pending?'处理中':mode==='return'?'确认退租':'确认丢失'}</button></form>}
function DepositForm({rental,submit,pending}:{rental:Rental;submit:(type:'押金退还'|'押金抵扣欠租'|'押金抵扣赔偿',amount:number,date:string,notes:string)=>void;pending:boolean}){const[value,setValue]=useState({type:'押金退还' as '押金退还'|'押金抵扣欠租'|'押金抵扣赔偿',amount:0,date:today(),notes:''});const balance=rental.ledger.reduce((sum,entry)=>sum+(entry.entryType==='押金收取'?Number(entry.amount):entry.entryType.startsWith('押金')?-Math.abs(Number(entry.amount)):0),0);return <form onSubmit={e=>{e.preventDefault();submit(value.type,value.amount,value.date,value.notes)}} className="flex flex-col gap-4"><p className="rounded-lg bg-muted p-3 text-sm">当前可用押金余额：<strong>{money(balance)}</strong></p><label className="flex flex-col gap-2 text-sm font-medium">处理类型<select className="h-10 rounded-lg border bg-background px-3" value={value.type} onChange={e=>setValue({...value,type:e.target.value as typeof value.type})}><option>押金退还</option><option>押金抵扣欠租</option><option>押金抵扣赔偿</option></select></label><Field label="金额（元）" type="number" value={value.amount} onChange={amount=>setValue({...value,amount:Number(amount)})}/><Field label="处理日期" type="date" value={value.date} onChange={date=>setValue({...value,date})}/><Field label="原因��凭证备注" value={value.notes} onChange={notes=>setValue({...value,notes})}/><button disabled={pending} className="h-10 rounded-lg bg-primary font-medium text-primary-foreground disabled:opacity-50">确认处理</button></form>}
function ExchangeForm({rental,submit,pending}:{rental:Rental;submit:(value:ExchangeInput)=>void;pending:boolean}){const[itemId,setItemId]=useState(rental.items[0]?.id||0);const[value,setValue]=useState<ExchangeInput>({rentalId:rental.id,rentalItemId:itemId,exchangeDate:today(),newDeviceName:'',newDeviceType:'台式机',newDeviceCode:'',newDeviceConfig:'',cpu:'',motherboard:'',memory:'',storage:'',graphicsCard:'',powerSupply:'',caseModel:'',monitorInfo:'',screenSize:'',screenResolution:'',refreshRate:'',panelType:'',ports:'',batteryInfo:'',adapterInfo:'',accessories:'',colorGamut:'',reason:'',notes:''});const update=(key:keyof ExchangeInput,next:string|number)=>setValue(current=>({...current,[key]:next}));return <form onSubmit={e=>{e.preventDefault();submit({...value,rentalItemId:itemId})}} className="flex flex-col gap-4"><label className="flex flex-col gap-2 text-sm font-medium">原设备<select className="h-10 rounded-lg border bg-background px-3" value={itemId} onChange={e=>setItemId(Number(e.target.value))}>{rental.items.map(item=><option key={item.id} value={item.id}>{item.deviceType} · {item.deviceName} · {item.deviceCode||'无编号'}</option>)}</select></label><div className="grid gap-4 sm:grid-cols-2"><Field label="换机日期" type="date" value={value.exchangeDate} onChange={next=>update('exchangeDate',next)}/><label className="flex flex-col gap-2 text-sm font-medium">新设备类型<select className="h-10 rounded-lg border bg-background px-3" value={value.newDeviceType} onChange={e=>update('newDeviceType',e.target.value)}>{['台式机','笔记本','显示器','一体机','其他'].map(type=><option key={type}>{type}</option>)}</select></label><Field label="新设备名称 / 型号" value={value.newDeviceName} onChange={next=>update('newDeviceName',next)}/><Field label="新设备编号" value={value.newDeviceCode} onChange={next=>update('newDeviceCode',next)}/>{(configs[value.newDeviceType]||[]).map(([key,label])=>{const exchangeKey=key as keyof ExchangeInput;return <Field key={key} label={label} value={String(value[exchangeKey]||'')} onChange={next=>update(exchangeKey,next)} required={false}/>})}{value.newDeviceType==='其他'&&<Field label="新设备配置" value={value.newDeviceConfig||''} onChange={next=>update('newDeviceConfig',next)} required={false}/>}<Field label="换机原因" value={value.reason} onChange={next=>update('reason',next)}/><Field label="备注" value={value.notes||''} onChange={next=>update('notes',next)} required={false}/></div><button disabled={pending} className="h-10 rounded-lg bg-primary font-medium text-primary-foreground disabled:opacity-50">确认换机</button></form>}
function itemToChange(item:Item):RentalChangeInput{return{rentalId:item.rentalId,itemId:item.id,eventDate:today(),reason:'',feeAdjustment:0,notes:'',deviceName:item.deviceName,deviceType:item.deviceType as RentalChangeInput['deviceType'],deviceCode:item.deviceCode||'',quantity:item.quantity,deviceConfig:item.deviceConfig||'',cpu:item.cpu||'',motherboard:item.motherboard||'',memory:item.memory||'',storage:item.storage||'',graphicsCard:item.graphicsCard||'',powerSupply:item.powerSupply||'',caseModel:item.caseModel||'',monitorInfo:item.monitorInfo||'',screenSize:item.screenSize||'',screenResolution:item.screenResolution||'',refreshRate:item.refreshRate||'',panelType:item.panelType||'',ports:item.ports||'',batteryInfo:item.batteryInfo||'',adapterInfo:item.adapterInfo||'',accessories:item.accessories||'',colorGamut:item.colorGamut||'',monthlyRent:Number(item.monthlyRent),totalRent:Number(item.totalRent)}}
function ChangeForm({rental,submit,pending}:{rental:Rental;submit:(value:RentalChangeInput)=>void;pending:boolean}){const first=rental.items[0];const[value,setValue]=useState<RentalChangeInput>(()=>first?itemToChange(first):({} as RentalChangeInput));if(!first)return <p>暂无可变更设备</p>;const update=(key:keyof RentalChangeInput,next:string|number)=>setValue(current=>({...current,[key]:next}));return <form onSubmit={e=>{e.preventDefault();submit(value)}} className="flex flex-col gap-4"><label className="flex flex-col gap-2 text-sm font-medium">设备明细<select value={value.itemId} onChange={e=>{const item=rental.items.find(current=>current.id===Number(e.target.value));if(item)setValue(itemToChange(item))}} className="h-10 rounded-lg border bg-background px-3">{rental.items.map(current=><option key={current.id} value={current.id}>{current.deviceType} · {current.deviceName} · {current.deviceCode||'无编��'}</option>)}</select></label><div className="grid gap-4 sm:grid-cols-2"><Field label="变更日期" type="date" value={value.eventDate} onChange={next=>update('eventDate',next)}/><Field label="变更原因" value={value.reason} onChange={next=>update('reason',next)}/><label className="flex flex-col gap-2 text-sm font-medium">设备类型<select className="h-10 rounded-lg border bg-background px-3" value={value.deviceType} onChange={e=>update('deviceType',e.target.value)}>{['台式机','笔记本','显示器','一体机','其他'].map(type=><option key={type}>{type}</option>)}</select></label><Field label="设备名称 / 型号" value={value.deviceName} onChange={next=>update('deviceName',next)}/><Field label="设备编号" value={value.deviceCode||''} onChange={next=>update('deviceCode',next)} required={false}/><Field label="调整后数量（只能增加）" type="number" value={value.quantity} onChange={next=>update('quantity',Math.max(first.quantity,Number(next)))}/>{(configs[value.deviceType]||[]).map(([key,label])=>{const changeKey=key as keyof RentalChangeInput;return <Field key={key} label={label} value={String(value[changeKey]||'')} onChange={next=>update(changeKey,next)} required={false}/>})}{value.deviceType==='其他'&&<Field label="设备配置" value={value.deviceConfig||''} onChange={next=>update('deviceConfig',next)} required={false}/>}<Field label="当前月租（元）" type="number" value={value.monthlyRent} onChange={next=>update('monthlyRent',Number(next))}/><Field label="调整后明细总额（元）" type="number" value={value.totalRent} onChange={next=>update('totalRent',Number(next))}/><Field label="本次应收调整（可填负数）" type="number" value={value.feeAdjustment} onChange={next=>update('feeAdjustment',Number(next))}/></div><label className="flex flex-col gap-2 text-sm font-medium">备注<textarea className="min-h-20 rounded-lg border bg-background p-3" value={value.notes||''} onChange={e=>update('notes',e.target.value)}/></label><button disabled={pending} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground disabled:opacity-50">{pending?'处理中':'确认变更'}</button></form>}
function RepairForm({rental,submit,pending}:{rental:Rental;submit:(value:RepairInput)=>void;pending:boolean}){const[value,setValue]=useState<RepairInput>({rentalId:rental.id,itemId:rental.items[0]?.id||0,eventDate:today(),status:'待维修',faultDescription:'',resolution:'',repairCost:0,customerCharge:0,completedDate:'',notes:''});return <form onSubmit={e=>{e.preventDefault();submit(value)}} className="flex flex-col gap-4"><div className="grid gap-4 sm:grid-cols-2"><label className="flex flex-col gap-2 text-sm font-medium">设备明细<select value={value.itemId} onChange={e=>setValue({...value,itemId:Number(e.target.value)})} className="h-10 rounded-lg border bg-background px-3">{rental.items.map(item=><option key={item.id} value={item.id}>{item.deviceType} · {item.deviceName} · {item.deviceCode||'无编号'}</option>)}</select></label><Field label="报修日期" type="date" value={value.eventDate} onChange={eventDate=>setValue({...value,eventDate})}/><label className="flex flex-col gap-2 text-sm font-medium">维修状态<select value={value.status} onChange={e=>setValue({...value,status:e.target.value as RepairInput['status']})} className="h-10 rounded-lg border bg-background px-3"><option>待维修</option><option>维修中</option><option>已完成</option></select></label><Field label="完成日期" type="date" value={value.completedDate||''} onChange={completedDate=>setValue({...value,completedDate})} required={false}/><Field label="维修总费用（元）" type="number" value={value.repairCost} onChange={repairCost=>setValue({...value,repairCost:Number(repairCost)})}/><Field label="客户承担金额（元）" type="number" value={value.customerCharge} onChange={customerCharge=>setValue({...value,customerCharge:Number(customerCharge)})}/></div><label className="flex flex-col gap-2 text-sm font-medium">故障描述<textarea required className="min-h-20 rounded-lg border bg-background p-3" value={value.faultDescription} onChange={e=>setValue({...value,faultDescription:e.target.value})}/></label><label className="flex flex-col gap-2 text-sm font-medium">处理方式<textarea className="min-h-20 rounded-lg border bg-background p-3" value={value.resolution||''} onChange={e=>setValue({...value,resolution:e.target.value})}/></label><label className="flex flex-col gap-2 text-sm font-medium">备注<textarea className="min-h-20 rounded-lg border bg-background p-3" value={value.notes||''} onChange={e=>setValue({...value,notes:e.target.value})}/></label><button disabled={pending} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground disabled:opacity-50">{pending?'处理中':'保存维修单'}</button></form>}
function BuyoutForm({rental,submit,pending}:{rental:Rental;submit:(itemId:number,quantity:number,price:number,date:string,notes:string)=>void;pending:boolean}){const available=rental.items.filter(i=>i.boughtOutQuantity<i.quantity);const[itemId,setItemId]=useState(available[0]?.id||0);const[quantity,setQuantity]=useState(1);const[price,setPrice]=useState(0);const[date,setDate]=useState(today());const[notes,setNotes]=useState('');const item=available.find(i=>i.id===itemId);return <form onSubmit={e=>{e.preventDefault();submit(itemId,quantity,price,date,notes)}} className="flex flex-col gap-4"><label className="flex flex-col gap-2 text-sm font-medium">设备明细<select className="h-11 rounded-lg border bg-background px-3" value={itemId} onChange={e=>{setItemId(Number(e.target.value));setQuantity(1)}}>{available.map(i=><option key={i.id} value={i.id}>{i.deviceType} · {i.deviceName} · {i.deviceCode||'无编号'}（剩余 {i.quantity-i.boughtOutQuantity} 台）</option>)}</select></label><div className="grid grid-cols-2 gap-4"><Field label="买断数量" type="number" value={quantity} onChange={v=>setQuantity(Number(v))}/><Field label="买断单价（元）" type="number" value={price} onChange={v=>setPrice(Number(v))}/><Field label="买断日期" type="date" value={date} onChange={setDate}/><div className="rounded-lg bg-muted p-3"><p className="text-xs text-muted-foreground">本次买断金额</p><p className="mt-1 text-lg font-semibold">{money(quantity*price)}</p></div></div>{item&&quantity>item.quantity-item.boughtOutQuantity&&<p className="text-sm text-destructive">买断数量不能超过剩余 {item.quantity-item.boughtOutQuantity} 台</p>}<label className="flex flex-col gap-2 text-sm font-medium">备注<textarea className="min-h-20 rounded-lg border bg-background p-3" value={notes} onChange={e=>setNotes(e.target.value)}/></label><button disabled={pending||!item||quantity<=0||price<=0||quantity>(item.quantity-item.boughtOutQuantity)} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground disabled:opacity-50">{pending?'处理中':'确认买断'}</button></form>}
function Dialog({open,title,children,onClose,wide=false}:{open:boolean;title:string;children:React.ReactNode;onClose:()=>void;wide?:boolean}){if(!open)return null;return <div className="fixed inset-0 z-50 flex items-center justify-center bg-foreground/20 p-4" onMouseDown={e=>{if(e.currentTarget===e.target)onClose()}}><div role="dialog" aria-modal="true" aria-label={title} className={`max-h-[92svh] w-full overflow-y-auto rounded-2xl border bg-card shadow-xl ${wide?'max-w-5xl':'max-w-lg'}`}><div className="sticky top-0 z-10 flex items-center justify-between border-b bg-card p-4"><h2 className="text-lg font-semibold">{title}</h2><button aria-label="关闭" onClick={onClose} className="rounded-lg p-2 hover:bg-muted"><X className="size-5"/></button></div><div className="p-4 sm:p-6">{children}</div></div></div>}
function FormSection({title,description,children}:{title:string;description:string;children:React.ReactNode}){return <fieldset className="flex flex-col gap-4 rounded-xl border p-4"><legend className="px-2 font-semibold">{title}</legend><p className="text-sm text-muted-foreground">{description}</p>{children}</fieldset>}
function Field({label,value,onChange,type='text',required=true,placeholder,readOnly=false}:{label:string;value:string|number;onChange:(value:string)=>void;type?:string;required?:boolean;placeholder?:string;readOnly?:boolean}){const integer=type==='number'&&/(数量|月数|天数)/.test(label);return <label className="flex flex-col gap-2 text-sm font-medium"><span>{label}{required&&!readOnly&&<span className="ml-1 text-destructive" aria-hidden="true">*</span>}</span><input className="h-10 rounded-lg border bg-background px-3 outline-none read-only:cursor-not-allowed read-only:bg-muted focus:ring-2 focus:ring-primary" type={type} inputMode={integer?'numeric':type==='number'?'decimal':undefined} value={value} onChange={e=>{if(integer&&e.target.value!==''&&!/^\d+$/.test(e.target.value))return;onChange(e.target.value)}} onFocus={e=>{if(type==='number'&&!readOnly)e.currentTarget.select()}} required={required} readOnly={readOnly} placeholder={placeholder} min={type==='number'&&label!=='本次应收调整（可填负数）'?'0':undefined} step={type==='number'?(integer?'1':'0.01'):undefined}/></label>}
function Stat({label,value,icon}:{label:string;value:string|number;icon:React.ReactNode}){return <div className="rounded-xl border bg-card p-4"><div className="mb-3 flex size-9 items-center justify-center rounded-lg bg-muted text-primary">{icon}</div><p className="text-sm text-muted-foreground">{label}</p><p className="mt-1 text-xl font-bold">{value}</p></div>}
function Status({value}:{value:string}){return <span className="inline-flex w-fit rounded-full bg-muted px-2.5 py-1 text-xs font-medium">{value}</span>}
function Info({l,v}:{l:string;v:string}){return <div><p className="text-xs text-muted-foreground">{l}</p><p className="mt-1 font-medium">{v}</p></div>}
function QuickAction({label,type,onSubmit,pending}:{label:string;type:string;onSubmit:(value:string)=>void;pending:boolean}){const[value,setValue]=useState('');return <form onSubmit={e=>{e.preventDefault();onSubmit(value)}} className="flex flex-col gap-4"><Field label={label} type={type} value={value} onChange={setValue}/><button disabled={pending} className="h-10 self-end rounded-lg bg-primary px-5 font-medium text-primary-foreground">{pending?'处理中':'确认提交'}</button></form>}
